function internship_fellowship_details_app_insert(&$error_message = '') {
	global $Translation;

	// mm: can member insert record?
	$arrPerm = getTablePermissions('internship_fellowship_details_app');
	if(!$arrPerm['insert']) {
		$error_message = $Translation['no insert permission'];
		return false;
	}

	$data = [
		'username' => parseCode('<%%creatorUsername%%>', true),
		'standard' => Request::val('standard', ''),
		'iittnif_id' => Request::val('iittnif_id', ''),
		'name_of_the_candidate' => Request::val('name_of_the_candidate', ''),
		'type_of_internship_fellowship' => Request::val('type_of_internship_fellowship', ''),
		'year' => Request::val('year', ''),
		'project_title' => br2nl(Request::val('project_title', '')),
		'gender' => Request::val('gender', 'Male'),
		'department' => Request::val('department', ''),
		'institute_id_number' => Request::val('institute_id_number', ''),
		'institute' => Request::val('institute', ''),
		'latitude' => Request::val('latitude', ''),
		'longitude' => Request::val('longitude', ''),
		'start_date' => Request::val('start_date', ''),
		'end_date' => Request::val('end_date', ''),
		'status' => Request::val('status', 'Yet to Start'),
		'cotegory' => Request::val('cotegory', ''),
		'report_link' => Request::val('report_link', ''),
		'outcomes' => br2nl(Request::val('outcomes', '')),
		'created_by' => parseCode('<%%creatorUsername%%>', true),
		'created_at' => parseCode('<%%creationDateTime%%>', true),
	];

	// record owner is current user
	$recordOwner = getLoggedMemberID();

	$recID = tableInsert('internship_fellowship_details_app', $data, $recordOwner, $error_message);

	// if this record is a copy of another record, copy children if applicable
	if(strlen(Request::val('SelectedID')) && $recID !== false)
		internship_fellowship_details_app_copy_children($recID, Request::val('SelectedID'));

	return $recID;
}

