		'type_of_internship_fellowship' => Request::val('type_of_internship_fellowship', ''),
		'year' => Request::val('year', ''),
		'project_title' => br2nl(Request::val('project_title', '')),
		'gender' => Request::val('gender', ''),
		'department' => Request::val('department', ''),
		'institute_id_number' => Request::val('institute_id_number', ''),
		'institute' => Request::val('institute', ''),
		'latitude' => Request::val('latitude', ''),
		'longitude' => Request::val('longitude', ''),
		'start_date' => Request::val('start_date', ''),
		'end_date' => Request::val('end_date', ''),
		'status' => Request::val('status', ''),
		'cotegory' => Request::val('cotegory', ''),
		'report_link' => Request::val('report_link', ''),
		'outcomes' => br2nl(Request::val('outcomes', '')),
		'last_updated_by' => parseCode('<%%editorUsername%%>', false),
		'last_updated_at' => parseCode('<%%editingDateTime%%>', false),
	];

	// get existing values
	$old_data = getRecord('internship_fellowship_details_app', $selected_id);
	if(is_array($old_data)) {
		$old_data = array_map('makeSafe', $old_data);
		$old_data['selectedID'] = makeSafe($selected_id);
	}

	$data['selectedID'] = makeSafe($selected_id);

	// hook: internship_fellowship_details_app_before_update
	if(function_exists('internship_fellowship_details_app_before_update')) {
		$args = ['old_data' => $old_data];
		if(!internship_fellowship_details_app_before_update($data, getMemberInfo(), $args)) {
			if(isset($args['error_message'])) $error_message = $args['error_message'];
			return false;
		}
	}

	$set = $data; unset($set['selectedID']);
	foreach ($set as $field => $value) {
		$set[$field] = ($value !== '' && $value !== NULL) ? $value : NULL;
	}

	if(!update(
		'internship_fellowship_details_app',
		backtick_keys_once($set),
		['`id`' => $selected_id],
		$error_message
	)) {
		echo $error_message;
		echo '<a href="internship_fellowship_details_app_view.php?SelectedID=' . urlencode($selected_id) . "\">{$Translation['< back']}</a>";
		exit;
	}


	update_calc_fields('internship_fellowship_details_app', $data['selectedID'], calculated_fields()['internship_fellowship_details_app']);

	// hook: internship_fellowship_details_app_after_update
	if(function_exists('internship_fellowship_details_app_after_update')) {
		if($row = getRecord('internship_fellowship_details_app', $data['selectedID'])) $data = array_map('makeSafe', $row);

		$data['selectedID'] = $data['id'];
		$args = ['old_data' => $old_data];
		if(!internship_fellowship_details_app_after_update($data, getMemberInfo(), $args)) return;
	}

	// mm: update record update timestamp
	set_record_owner('internship_fellowship_details_app', $selected_id);
}

